--
-- Table structure for table `sales_statistics`
--

DROP TABLE IF EXISTS `sales_statistics`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `sales_statistics` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '统计ID',
  `date` date NOT NULL COMMENT '统计日期',
  `vending_machine_id` int(11) DEFAULT NULL COMMENT '售货机ID',
  `product_id` int(11) DEFAULT NULL COMMENT '商品ID',
  `sales_quantity` int(11) DEFAULT '0' COMMENT '销售数量',
  `sales_amount` decimal(10,2) DEFAULT '0.00' COMMENT '销售金额',
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_date_machine_product` (`date`,`vending_machine_id`,`product_id`),
  KEY `vending_machine_id` (`vending_machine_id`),
  KEY `product_id` (`product_id`),
  CONSTRAINT `sales_statistics_ibfk_1` FOREIGN KEY (`vending_machine_id`) REFERENCES `vending_machines` (`id`) ON DELETE CASCADE,
  CONSTRAINT `sales_statistics_ibfk_2` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='销售统计表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `sales_statistics`
--

LOCK TABLES `sales_statistics` WRITE;
/*!40000 ALTER TABLE `sales_statistics` DISABLE KEYS */;
/*!40000 ALTER TABLE `sales_statistics` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `users`
--

DROP TABLE IF EXISTS `users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `users` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '用户ID',
  `username` varchar(50) NOT NULL COMMENT '用户名',
  `password` varchar(255) NOT NULL COMMENT '密码',
  `balance` decimal(10,2) DEFAULT '0.00' COMMENT '账户余额',
  `role` enum('user','admin') DEFAULT 'user' COMMENT '用户角色',
  `status` enum('active','inactive') DEFAULT 'active' COMMENT '用户状态',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `last_login` datetime DEFAULT NULL COMMENT '最后登录时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=2001 DEFAULT CHARSET=utf8mb4 COMMENT='用户表';
/*!40101 SET character_set_client = @saved_cs_client */;

