--
-- Table structure for table `vending_machines`
--

DROP TABLE IF EXISTS `vending_machines`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `vending_machines` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '售货机ID',
  `name` varchar(50) NOT NULL COMMENT '售货机名称',
  `location` varchar(100) NOT NULL COMMENT '售货机位置',
  `status` enum('在线','离线','故障','维护中') DEFAULT '离线' COMMENT '售货机状态',
  `temperature` decimal(5,2) DEFAULT NULL COMMENT '温度',
  `humidity` decimal(5,2) DEFAULT NULL COMMENT '湿度',
  `last_online` datetime DEFAULT NULL COMMENT '最后在线时间',
  `last_maintenance` datetime DEFAULT NULL COMMENT '最后维护时间',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_vending_machines_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=101 DEFAULT CHARSET=utf8mb4 COMMENT='售货机表';
/*!40101 SET character_set_client = @saved_cs_client */;

